WITH item_summary AS ( SELECT b.move_req_id , MIN(b.item_cd) AS rep_item_cd , SUM(b.qty) AS qty , COUNT(DISTINCT b.item_cd) AS item_cnt FROM tb_move_stock_item b GROUP BY b.move_req_id ), rep_item AS ( SELECT s.move_req_id , c.item_name AS rep_item_name , s.qty , s.item_cnt FROM item_summary s INNER JOIN tb_item_mst c ON s.rep_item_cd = c.item_cd ) SELECT CONCAT(CONVERT(varchar(10), a.move_req_date, 23), ' - ', a.seq) AS moveReqDateSeq , c.storage_name as src_storage_name , d.storage_name as tar_storage_name , b.member_nm as manager_name , dbo.getCommonName('MOVE_STATUS', a.move_status) as move_status_name , a.src_storage_cd , a.tar_storage_cd , CASE WHEN r.item_cnt > 1 THEN CONCAT(r.rep_item_name, ' 외 ', r.item_cnt - 1, '건') ELSE r.rep_item_name END AS item_name , a.memo , r.qty , a.manager_id , a.move_status , a.move_req_id FROM tb_move_req a INNER JOIN rep_item r ON a.move_stock_id = r.move_stock_id inner join tb_users b on a.manager_id = b.user_id inner join tb_storage_mst c on a.src_storage_cd = c.storage_cd inner join tb_storage_mst d on a.tar_storage_cd = d.storage_cd WHERE a.move_stock_date BETWEEN #{strDate} AND #{endDate}
AND a.move_status = #{moveStatus}
AND a.src_storage_cd = #{srcStorageCd}
AND a.tar_storage_cd = #{tarStorageCd}
AND EXISTS (SELECT 1 FROM tb_move_stock_item b WHERE b.move_stock_id = a.move_stock_id AND b.item_cd LIKE '%' + #{itemCd} + '%' )
AND EXISTS (SELECT 1 FROM tb_move_stock_item b INNER JOIN tb_item_mst c ON b.item_cd = c.item_cd WHERE b.move_stock_id = a.move_stock_id AND c.item_name LIKE '%' + #{itemName} + '%' )
ORDER BY a.move_stock_date DESC, a.seq DESC

mapper.update:
update tb_move_stock
set    move_status      = #{moveStatus}
      ,manager_id       = #{managerId}
      ,confirmer_id     = #{confirmerId}
      ,etc              = #{etc}
      ,upd_id           = #{userId}
      ,upd_dt           = getdate()
where  move_stock_id    = #{moveStockId}

UPDATE tb_move_stock_item
SET item_type_cd = #{itemTypeCd}
  , item_cd      = #{itemCd}
  , test_no      = #{testNo}
  , qty          = #{qty}
  , upd_id       = #{userId}
  , upd_dt       = GETDATE()
where MoveStockItemId = #{moveStockItemId}
and
